package sneak.snaek.strategy;

import sneak.snaek.board.BoardGrid;
import sneak.snaek.board.CoordUtils;
import sneak.snaek.model.BattleSnake;
import sneak.snaek.model.Coord;
import sneak.snaek.model.Move;

import java.util.*;

/**
 * One-ply move scoring.
 *
 *   score(move) = survival(area, length)            // flood-fill, trap-aware
 *               + foodBonus(weight, myDist)         // iff we win a food race
 *               + tailBonus(BFS dist to own tail)   // open-space tiebreaker
 *
 * Enemy BFS (distance + ownership) is hoisted to the caller — see
 * {@link #computeEnemyReach}. It is identical for every candidate move
 * so doing it once per turn (not per move) cuts per-turn BFS by ~50%.
 */
public final class MoveScorer {

    /** Maximum food-race weight. Sized to be the dominant *positional*
     *  signal among the bonuses (TAIL_BONUS=100, H2H_KILL_BONUS=200,
     *  CENTER_BONUS=100) so winnable food still pulls reliably — but
     *  capped at TRAP_PENALTY (1 000) so it can never coax us into a
     *  trap, and small enough that a clear survival-area difference
     *  (Voronoi-weighted, range 0…2·length) can override it when the
     *  food cell is in tight space. The lead dampener (see
     *  {@link #computeFoodWeight}) scales this down further as we pull
     *  ahead. Was 10 000 — that overpowered survival in close calls. */
    private static final double FOOD_BONUS    = 500.0;
    /** Heavy penalty applied when the survival pocket (raw owned cells)
     *  is smaller than our body length — i.e. we'd self-collide before
     *  the tail vacates, or be sealed in by an enemy cutoff. Sized to
     *  beat any non-trapped alternative (max non-trapped survival ≈
     *  2·length ≈ 200) yet stay finite so the bot can still pick a
     *  trapped cell when *every* option is trapped (least-bad mode). */
    private static final double TRAP_PENALTY  = 1_000.0;
    /** Max bonus for moving toward our own tail. Acts as a directional
     *  tiebreaker in open space — preventing the long-snake "wander
     *  into a U-shape and seal it" failure mode. Sized below food/H2H
     *  so it never overrides intent, but above 0 so equal-survival
     *  moves prefer following the body loop. */
    private static final double TAIL_BONUS    = 100.0;
    /** Cap the survival-area term at this multiple of our length when
     *  NOT trapped. Past this point all moves are "equally safe" and
     *  the tail/centre tiebreakers are allowed to steer; otherwise an
     *  open-board snake would just chase the largest pocket forever. */
    private static final int    AREA_CAP_MULT = 3;
    /** Length lead (over the longest live enemy) at which we start
     *  dampening the food bonus. At lead ≤ THRESHOLD the chase is at
     *  full FOOD_BONUS; past it the weight decays as 1/(1+excess) —
     *  see {@link #computeFoodWeight}. Larger ⇒ stay aggressive longer. */
    private static final int    LEAD_THRESHOLD = 4;
    /** Direct cost for stepping the head into a hazard cell. Roughly the
     *  HP drain per turn in default Royale (15). Scaled to be visible
     *  against open-space tail tiebreakers (TAIL_BONUS=100) but small
     *  enough that a winnable food (FOOD_BONUS) still overrides. */
    private static final double HAZARD_PENALTY = 25.0;
    /** Weight of hazard cells when counting the survival/flood-fill area.
     *  Hazards are passable but drain HP, so a pocket made mostly of
     *  hazard cells is effectively smaller than its raw cell count. */
    private static final double HAZARD_AREA_WEIGHT = 0.25;
    /** Bonus for moves that land adjacent to a strictly shorter enemy's head.
     *  We'd win that head-to-head if they step into us — and even if they
     *  avoid the cell, we've taken away a legal move from them, sometimes
     *  forcing them into a wall or their own body. Sized between TAIL_BONUS
     *  (100) and FOOD_BONUS(1000): meaningful in open space, won't
     *  override food or trap detection. */
    private static final double H2H_KILL_BONUS = 200.0;
    /** Soft preference for cells closer to the board centre. Edges are
     *  more easily cut off (a wall already blocks one side). Sized small
     *  so it never overrides survival, food, h2h pressure, or tail-chase
     *  in late-game tight loops — purely a mid-game positional tiebreaker
     *  when other terms are flat. */
    private static final double CENTER_BONUS = 100.0;
    /** Sentinel BFS distance for "no path" / out-of-bounds. Use
     *  {@code Integer.MAX_VALUE} so {@code dist > d + 1} relaxation
     *  works without overflow checks. */
    static final int            UNREACHABLE   = Integer.MAX_VALUE;

    private MoveScorer() {}

    /** Holder for the once-per-turn enemy BFS result. */
    public record EnemyReach(int[][] dist, int[][] owner) {}

    /**
     * Per-component score breakdown for a single candidate move.
     * Total = survival + food + tail + h2h + centre − hazardPenalty.
     * Diagnostic fields ({@code trapped}, {@code ownedRaw}) help explain
     * why the bot picked a move when reading the logs.
     */
    public record Score(double total,
                        double survival,
                        double food,
                        double tail,
                        double h2h,
                        double centre,
                        double hazardPenalty,
                        boolean trapped,
                        int    ownedRaw) {
        @Override public String toString() {
            return String.format(
                "total=%.1f survival=%.1f food=%.1f tail=%.1f h2h=%.1f centre=%.1f hazard=-%.1f trapped=%s owned=%d",
                total, survival, food, tail, h2h, centre, hazardPenalty, trapped, ownedRaw);
        }
    }

    public static Score score(BoardGrid grid,
                              Coord myHead,
                              int myLength,
                              Coord myTail,
                              Move move,
                              List<BattleSnake> enemies,
                              Set<Coord> food,
                              EnemyReach enemyReach,
                              double foodWeight) {

        Coord next = CoordUtils.neighbor(myHead, move);

        // Single BFS from the candidate cell — reused for survival, tail, food.
        int[][] myDist = bfs(grid, List.of(next));

        // 1. Survival via Voronoi-weighted reachable area.
        //    For each reachable cell, count it ONLY if we win the race
        //    against the enemy — strictly closer, OR tied and we'd win
        //    the head-to-head (longer than the contesting enemy). This
        //    catches "small enemy can cut me off mid-corridor" traps
        //    that pure flood-fill misses (timing matters more than length —
        //    even a 12-length snake can seal a 47-length one).
        //    Hazard cells contribute HAZARD_AREA_WEIGHT to the weighted
        //    sum. Trap detection uses the *raw owned count* vs body length:
        //    if cells we'll actually control don't fit our body, we'll
        //    tail-collide or be sealed in regardless of total reachable.
        VoronoiArea owned = voronoiArea(myDist, enemyReach, enemies, myLength, grid);
        boolean trapped = owned.rawCount < myLength;
        double survival = trapped
                ? owned.weighted - TRAP_PENALTY
                : Math.min(owned.weighted, AREA_CAP_MULT * myLength);

        // 1b. Direct hazard step penalty — a clean alternative beats a
        //     hazard step at equal area; food still overrides.
        double hazardPenalty = grid.isHazard(next) ? HAZARD_PENALTY : 0.0;

        // 1c. H2H aggression: bonus for moves that threaten a strictly
        //     shorter enemy's head. If they step into us we eat them; if
        //     they avoid the cell we've still removed one of their legal
        //     moves. Skip when trapped — survival comes first. Take the
        //     max over enemies (pressing one is what matters; two-front
        //     pressure is rare and not double-counted).
        double h2hBonus = 0.0;
        if (!trapped) {
            for (BattleSnake enemy : enemies) {
                if (enemy.length() >= myLength) continue;
                if (CoordUtils.manhattanDistance(next, enemy.head()) == 1) {
                    h2hBonus = H2H_KILL_BONUS;
                    break;
                }
            }
        }

        // 2. Tail-chase tiebreaker: BFS distance to our own tail.
        //    Manhattan was misleading in cluttered states (tail "close"
        //    by air-distance but unreachable by path). If the tail cell
        //    itself is blocked (recent eat → tail won't vacate), fall
        //    back to the nearest reachable neighbour of the tail.
        int tailDist = at(myDist, myTail);
        if (tailDist >= UNREACHABLE) {
            for (Coord n : CoordUtils.neighbors(myTail)) {
                int v = at(myDist, n);
                if (v < tailDist) tailDist = v;
            }
        }
        double tailBonus = tailDist >= UNREACHABLE
                ? 0.0
                : TAIL_BONUS / (1.0 + tailDist);

        // 2b. Centre-preference tiebreaker. Chebyshev distance to the
        //     board centre — at the dead centre the bonus is full
        //     CENTER_BONUS, decaying as 1/(1+d). On an 11×11 board the
        //     edge cells score ~8 vs the centre's 50.
        int cx = (grid.getWidth()  - 1) / 2;
        int cy = (grid.getHeight() - 1) / 2;
        int centreDist = Math.max(Math.abs(next.x() - cx), Math.abs(next.y() - cy));
        double centreBonus = CENTER_BONUS / (1.0 + centreDist);

        // 3. Food race — strictly closer, OR tied & we win the H2H.
        //    Skipped entirely when trapped (food in a death pocket is bait).
        double foodBonus = 0.0;
        if (!trapped && !food.isEmpty()) {
            int[][] enemyDist  = enemyReach.dist();
            int[][] enemyOwner = enemyReach.owner();
            for (Coord f : food) {
                int md = at(myDist, f);
                if (md >= UNREACHABLE) continue;
                int ed = at(enemyDist, f);
                boolean win;
                if (md < ed) {
                    win = true;
                } else if (md == ed) {
                    int ownerIdx = enemyOwner[f.x()][f.y()];
                    win = ownerIdx >= 0
                            && myLength > enemies.get(ownerIdx).length();
                } else {
                    win = false;
                }
                if (win) {
                    foodBonus = Math.max(foodBonus, foodWeight / (1.0 + md));
                }
            }
        }
        double total = survival + foodBonus + tailBonus + h2hBonus + centreBonus - hazardPenalty;
        return new Score(total, survival, foodBonus, tailBonus, h2hBonus,
                centreBonus, hazardPenalty, trapped, owned.rawCount);
    }

    // -----------------------------------------------------------------------
    // Per-turn helpers (compute once in SnakeEngine, reuse for every candidate)
    // -----------------------------------------------------------------------

    /** Multi-source BFS from all enemy heads, recording first-arrival owner. */
    public static EnemyReach computeEnemyReach(BoardGrid grid,
                                               List<BattleSnake> enemies) {
        int w = grid.getWidth(), h = grid.getHeight();
        int[][] dist  = new int[w][h];
        int[][] owner = new int[w][h];
        bfsWithOwners(grid,
                enemies.stream().map(BattleSnake::head).toList(),
                dist, owner);
        return new EnemyReach(dist, owner);
    }

    /**
     * Smooth gradient on the food bonus weight based on length lead.
     *   foodWeight = FOOD_BONUS / (1 + max(0, lead - LEAD_THRESHOLD))
     * Solo play keeps full weight — growing is the only goal.
     */
    public static double computeFoodWeight(int myLength,
                                           List<BattleSnake> enemies) {
        if (enemies.isEmpty()) return FOOD_BONUS;
        int maxEnemyLen = enemies.stream().mapToInt(BattleSnake::length).max().orElse(0);
        int lead        = myLength - maxEnemyLen;
        int excess      = Math.max(0, lead - LEAD_THRESHOLD);
        return FOOD_BONUS / (1.0 + excess);
    }

    // -----------------------------------------------------------------------
    // BFS internals
    // -----------------------------------------------------------------------

    private static int[][] bfs(BoardGrid grid, List<Coord> sources) {
        int w = grid.getWidth(), h = grid.getHeight();
        int[][] dist = new int[w][h];
        for (int[] row : dist) Arrays.fill(row, UNREACHABLE);

        Deque<Coord> queue = new ArrayDeque<>();
        for (Coord src : sources) {
            if (!grid.inBounds(src)) continue;
            if (dist[src.x()][src.y()] == UNREACHABLE) {
                dist[src.x()][src.y()] = 0;
                queue.add(src);
            }
        }
        while (!queue.isEmpty()) {
            Coord c = queue.poll();
            int d = dist[c.x()][c.y()];
            for (Coord n : CoordUtils.neighbors(c)) {
                if (!grid.inBounds(n) || grid.isBlocked(n)) continue;
                if (dist[n.x()][n.y()] > d + 1) {
                    dist[n.x()][n.y()] = d + 1;
                    queue.add(n);
                }
            }
        }
        return dist;
    }

    private static void bfsWithOwners(BoardGrid grid, List<Coord> sources,
                                      int[][] dist, int[][] owner) {
        for (int[] row : dist)  Arrays.fill(row, UNREACHABLE);
        for (int[] row : owner) Arrays.fill(row, -1);

        Deque<int[]> queue = new ArrayDeque<>();
        for (int i = 0; i < sources.size(); i++) {
            Coord src = sources.get(i);
            if (!grid.inBounds(src)) continue;
            if (dist[src.x()][src.y()] == UNREACHABLE) {
                dist[src.x()][src.y()]  = 0;
                owner[src.x()][src.y()] = i;
                queue.add(new int[]{src.x(), src.y(), i});
            }
        }
        while (!queue.isEmpty()) {
            int[] cur = queue.poll();
            int cx = cur[0], cy = cur[1], oi = cur[2];
            int d  = dist[cx][cy];
            for (Coord n : CoordUtils.neighbors(new Coord(cx, cy))) {
                if (!grid.inBounds(n) || grid.isBlocked(n)) continue;
                if (dist[n.x()][n.y()] > d + 1) {
                    dist[n.x()][n.y()]  = d + 1;
                    owner[n.x()][n.y()] = oi;
                    queue.add(new int[]{n.x(), n.y(), oi});
                }
            }
        }
    }

    /** Result of computing our Voronoi region from a candidate cell. */
    private record VoronoiArea(int rawCount, double weighted) {}

    /**
     * Cells we win the race to from {@code myDist}'s source, with hazard
     * weighting. A cell counts iff {@code myDist[c] < enemyDist[c]}, OR
     * {@code myDist[c] == enemyDist[c]} AND we are strictly longer than
     * the closest contesting enemy (we'd win the H2H if both arrived).
     * In solo (no enemies), {@code enemyDist} is all UNREACHABLE → every
     * reachable cell is owned, identical to a plain flood-fill.
     */
    private static VoronoiArea voronoiArea(int[][] myDist,
                                           EnemyReach enemyReach,
                                           List<BattleSnake> enemies,
                                           int myLength,
                                           BoardGrid grid) {
        int[][] enemyDist  = enemyReach.dist();
        int[][] enemyOwner = enemyReach.owner();
        int    raw      = 0;
        double weighted = 0.0;
        for (int x = 0; x < myDist.length; x++) {
            for (int y = 0; y < myDist[0].length; y++) {
                int md = myDist[x][y];
                if (md >= UNREACHABLE) continue;
                int ed = enemyDist[x][y];
                boolean own;
                if (md < ed) {
                    own = true;
                } else if (md == ed) {
                    int oi = enemyOwner[x][y];
                    own = oi >= 0 && myLength > enemies.get(oi).length();
                } else {
                    own = false;
                }
                if (own) {
                    raw++;
                    weighted += grid.isHazard(new Coord(x, y)) ? HAZARD_AREA_WEIGHT : 1.0;
                }
            }
        }
        return new VoronoiArea(raw, weighted);
    }

    private static int at(int[][] dist, Coord c) {
        if (c.x() < 0 || c.y() < 0 || c.x() >= dist.length || c.y() >= dist[0].length) {
            return UNREACHABLE;
        }
        return dist[c.x()][c.y()];
    }
}

package sneak.snaek.strategy;

import sneak.snaek.board.BoardGrid;
import sneak.snaek.board.CoordUtils;
import sneak.snaek.model.BattleSnake;
import sneak.snaek.model.Coord;
import sneak.snaek.model.Move;

import java.util.*;

/**
 * One-ply move scoring.
 *
 *   score(move) = survival(area, length)            // flood-fill, trap-aware
 *               + foodBonus(weight, myDist)         // iff we win a food race
 *               + tailBonus(BFS dist to own tail)   // open-space tiebreaker
 *
 * Enemy BFS (distance + ownership) is hoisted to the caller — see
 * {@link #computeEnemyReach}. It is identical for every candidate move
 * so doing it once per turn (not per move) cuts per-turn BFS by ~50%.
 */
public final class MoveScorer {

    /** Maximum food-race weight. Sized to be the dominant *positional*
     *  signal among the bonuses (TAIL_BONUS=100, H2H_KILL_BONUS=200,
     *  CENTER_BONUS=100) so winnable food still pulls reliably — but
     *  capped at TRAP_PENALTY (1 000) so it can never coax us into a
     *  trap, and small enough that a clear survival-area difference
     *  (Voronoi-weighted, range 0…2·length) can override it when the
     *  food cell is in tight space. The lead dampener (see
     *  {@link #computeFoodWeight}) scales this down further as we pull
     *  ahead. Was 10 000 — that overpowered survival in close calls. */
    private static final double FOOD_BONUS    = 500.0;
    /** Heavy penalty applied when the survival pocket (raw owned cells)
     *  is smaller than our body length — i.e. we'd self-collide before
     *  the tail vacates, or be sealed in by an enemy cutoff. Sized to
     *  beat any non-trapped alternative (max non-trapped survival ≈
     *  2·length ≈ 200) yet stay finite so the bot can still pick a
     *  trapped cell when *every* option is trapped (least-bad mode). */
    private static final double TRAP_PENALTY  = 1_000.0;
    /** Max bonus for moving toward our own tail. Acts as a directional
     *  tiebreaker in open space — preventing the long-snake "wander
     *  into a U-shape and seal it" failure mode. Sized below food/H2H
     *  so it never overrides intent, but above 0 so equal-survival
     *  moves prefer following the body loop. */
    private static final double TAIL_BONUS    = 100.0;
    /** Cap the survival-area term at this multiple of our length when
     *  NOT trapped. Past this point all moves are "equally safe" and
     *  the tail/centre tiebreakers are allowed to steer; otherwise an
     *  open-board snake would just chase the largest pocket forever. */
    private static final int    AREA_CAP_MULT = 3;
    /** Length lead (over the longest live enemy) at which we start
     *  dampening the food bonus. At lead ≤ THRESHOLD the chase is at
     *  full FOOD_BONUS; past it the weight decays as 1/(1+excess) —
     *  see {@link #computeFoodWeight}. Larger ⇒ stay aggressive longer. */
    private static final int    LEAD_THRESHOLD = 4;
    /** Direct cost for stepping the head into a hazard cell. Roughly the
     *  HP drain per turn in default Royale (15). Scaled to be visible
     *  against open-space tail tiebreakers (TAIL_BONUS=100) but small
     *  enough that a winnable food (FOOD_BONUS) still overrides. */
    private static final double HAZARD_PENALTY = 25.0;
    /** Weight of hazard cells when counting the survival/flood-fill area.
     *  Hazards are passable but drain HP, so a pocket made mostly of
     *  hazard cells is effectively smaller than its raw cell count. */
    private static final double HAZARD_AREA_WEIGHT = 0.25;
    /** Bonus for moves that land adjacent to a strictly shorter enemy's head.
     *  We'd win that head-to-head if they step into us — and even if they
     *  avoid the cell, we've taken away a legal move from them, sometimes
     *  forcing them into a wall or their own body. Sized between TAIL_BONUS
     *  (100) and FOOD_BONUS(1000): meaningful in open space, won't
     *  override food or trap detection. */
    private static final double H2H_KILL_BONUS = 200.0;
    /** Soft preference for cells closer to the board centre. Edges are
     *  more easily cut off (a wall already blocks one side). Sized small
     *  so it never overrides survival, food, h2h pressure, or tail-chase
     *  in late-game tight loops — purely a mid-game positional tiebreaker
     *  when other terms are flat. */
    private static final double CENTER_BONUS = 100.0;
    /** Sentinel BFS distance for "no path" / out-of-bounds. Use
     *  {@code Integer.MAX_VALUE} so {@code dist > d + 1} relaxation
     *  works without overflow checks. */
    static final int            UNREACHABLE   = Integer.MAX_VALUE;

    private MoveScorer() {}

    /** Holder for the once-per-turn enemy BFS result. */
    public record EnemyReach(int[][] dist, int[][] owner) {}

    /**
     * Per-component score breakdown for a single candidate move.
     * Total = survival + food + tail + h2h + centre − hazardPenalty.
     * Diagnostic fields ({@code trapped}, {@code ownedRaw}) help explain
     * why the bot picked a move when reading the logs.
     */
    public record Score(double total,
                        double survival,
                        double food,
                        double tail,
                        double h2h,
                        double centre,
                        double hazardPenalty,
                        boolean trapped,
                        int    ownedRaw) {
        @Override public String toString() {
            return String.format(
                "total=%.1f survival=%.1f food=%.1f tail=%.1f h2h=%.1f centre=%.1f hazard=-%.1f trapped=%s owned=%d",
                total, survival, food, tail, h2h, centre, hazardPenalty, trapped, ownedRaw);
        }
    }

    public static Score score(BoardGrid grid,
                              Coord myHead,
                              int myLength,
                              Coord myTail,
                              Move move,
                              List<BattleSnake> enemies,
                              Set<Coord> food,
                              EnemyReach enemyReach,
                              double foodWeight) {

        Coord next = CoordUtils.neighbor(myHead, move);

        // Single BFS from the candidate cell — reused for survival, tail, food.
        int[][] myDist = bfs(grid, List.of(next));

        // Tail-chase reachability check (computed early — feeds trap detection).
        // If we can reach our own tail through unblocked cells, we have a
        // guaranteed survival loop: each turn our tail vacates one cell, we
        // step forward by one, the loop is self-sustaining indefinitely.
        // Tail cell itself may be blocked (recent eat → won't vacate yet),
        // in which case fall back to the nearest reachable neighbour of
        // the tail — that's the segment that *will* be the tail next turn.
        int tailDist = at(myDist, myTail);
        if (tailDist >= UNREACHABLE) {
            for (Coord n : CoordUtils.neighbors(myTail)) {
                int v = at(myDist, n);
                if (v < tailDist) tailDist = v;
            }
        }
        boolean canReachTail = tailDist < UNREACHABLE;

        // 1. Survival via Voronoi-weighted reachable area.
        //    For each reachable cell, count it ONLY if we win the race
        //    against the enemy — strictly closer, OR tied and we'd win
        //    the head-to-head (longer than the contesting enemy). This
        //    catches "small enemy can cut me off mid-corridor" traps
        //    that pure flood-fill misses (timing matters more than length —
        //    even a 12-length snake can seal a 47-length one).
        //    Hazard cells contribute HAZARD_AREA_WEIGHT to the weighted
        //    sum. Trap detection: raw owned cells must hold our body OR
        //    we must be able to chase our own tail (sustainable loop —
        //    the body itself vacates as we move). Either condition is
        //    sufficient for survival; only fail both ⇒ truly trapped.
        VoronoiArea owned = voronoiArea(myDist, enemyReach, enemies, myLength, grid);
        boolean trapped = owned.rawCount < myLength && !canReachTail;
        double survival = trapped
                ? owned.weighted - TRAP_PENALTY
                : Math.min(owned.weighted, AREA_CAP_MULT * myLength);

        // 1b. Direct hazard step penalty — a clean alternative beats a
        //     hazard step at equal area; food still overrides.
        double hazardPenalty = grid.isHazard(next) ? HAZARD_PENALTY : 0.0;

        // 1c. H2H aggression: bonus for moves that threaten a strictly
        //     shorter enemy's head. If they step into us we eat them; if
        //     they avoid the cell we've still removed one of their legal
        //     moves. Skip when trapped — survival comes first. Take the
        //     max over enemies (pressing one is what matters; two-front
        //     pressure is rare and not double-counted).
        double h2hBonus = 0.0;
        if (!trapped) {
            for (BattleSnake enemy : enemies) {
                if (enemy.length() >= myLength) continue;
                if (CoordUtils.manhattanDistance(next, enemy.head()) == 1) {
                    h2hBonus = H2H_KILL_BONUS;
                    break;
                }
            }
        }

        // 2. Tail-chase tiebreaker: BFS distance to our own tail.
        //    (Reachability was checked above for trap detection; reuse
        //    the same distance to scale the bonus — closer = stronger
        //    pull toward the safe loop.)
        double tailBonus = canReachTail
                ? TAIL_BONUS / (1.0 + tailDist)
                : 0.0;

        // 2b. Centre-preference tiebreaker. Chebyshev distance to the
        //     board centre — at the dead centre the bonus is full
        //     CENTER_BONUS, decaying as 1/(1+d). On an 11×11 board the
        //     edge cells score ~8 vs the centre's 50.
        int cx = (grid.getWidth()  - 1) / 2;
        int cy = (grid.getHeight() - 1) / 2;
        int centreDist = Math.max(Math.abs(next.x() - cx), Math.abs(next.y() - cy));
        double centreBonus = CENTER_BONUS / (1.0 + centreDist);

        // 3. Food race — strictly closer, OR tied & we win the H2H.
        //    Skipped entirely when trapped (food in a death pocket is bait).
        double foodBonus = 0.0;
        if (!trapped && !food.isEmpty()) {
            int[][] enemyDist  = enemyReach.dist();
            int[][] enemyOwner = enemyReach.owner();
            for (Coord f : food) {
                int md = at(myDist, f);
                if (md >= UNREACHABLE) continue;
                int ed = at(enemyDist, f);
                boolean win;
                if (md < ed) {
                    win = true;
                } else if (md == ed) {
                    int ownerIdx = enemyOwner[f.x()][f.y()];
                    win = ownerIdx >= 0
                            && myLength > enemies.get(ownerIdx).length();
                } else {
                    win = false;
                }
                if (win) {
                    foodBonus = Math.max(foodBonus, foodWeight / (1.0 + md));
                }
            }
        }
        double total = survival + foodBonus + tailBonus + h2hBonus + centreBonus - hazardPenalty;
        return new Score(total, survival, foodBonus, tailBonus, h2hBonus,
                centreBonus, hazardPenalty, trapped, owned.rawCount);
    }

    // -----------------------------------------------------------------------
    // Per-turn helpers (compute once in SnakeEngine, reuse for every candidate)
    // -----------------------------------------------------------------------

    /** Multi-source BFS from all enemy heads, recording first-arrival owner. */
    public static EnemyReach computeEnemyReach(BoardGrid grid,
                                               List<BattleSnake> enemies) {
        int w = grid.getWidth(), h = grid.getHeight();
        int[][] dist  = new int[w][h];
        int[][] owner = new int[w][h];
        bfsWithOwners(grid,
                enemies.stream().map(BattleSnake::head).toList(),
                dist, owner);
        return new EnemyReach(dist, owner);
    }

    /**
     * Smooth gradient on the food bonus weight based on length lead.
     *   foodWeight = FOOD_BONUS / (1 + max(0, lead - LEAD_THRESHOLD))
     * Solo play keeps full weight — growing is the only goal.
     */
    public static double computeFoodWeight(int myLength,
                                           List<BattleSnake> enemies) {
        if (enemies.isEmpty()) return FOOD_BONUS;
        int maxEnemyLen = enemies.stream().mapToInt(BattleSnake::length).max().orElse(0);
        int lead        = myLength - maxEnemyLen;
        int excess      = Math.max(0, lead - LEAD_THRESHOLD);
        return FOOD_BONUS / (1.0 + excess);
    }

    // -----------------------------------------------------------------------
    // BFS internals
    // -----------------------------------------------------------------------

    private static int[][] bfs(BoardGrid grid, List<Coord> sources) {
        int w = grid.getWidth(), h = grid.getHeight();
        int[][] dist = new int[w][h];
        for (int[] row : dist) Arrays.fill(row, UNREACHABLE);

        Deque<Coord> queue = new ArrayDeque<>();
        for (Coord src : sources) {
            if (!grid.inBounds(src)) continue;
            if (dist[src.x()][src.y()] == UNREACHABLE) {
                dist[src.x()][src.y()] = 0;
                queue.add(src);
            }
        }
        while (!queue.isEmpty()) {
            Coord c = queue.poll();
            int d = dist[c.x()][c.y()];
            for (Coord n : CoordUtils.neighbors(c)) {
                if (!grid.inBounds(n) || grid.isBlocked(n)) continue;
                if (dist[n.x()][n.y()] > d + 1) {
                    dist[n.x()][n.y()] = d + 1;
                    queue.add(n);
                }
            }
        }
        return dist;
    }

    private static void bfsWithOwners(BoardGrid grid, List<Coord> sources,
                                      int[][] dist, int[][] owner) {
        for (int[] row : dist)  Arrays.fill(row, UNREACHABLE);
        for (int[] row : owner) Arrays.fill(row, -1);

        Deque<int[]> queue = new ArrayDeque<>();
        for (int i = 0; i < sources.size(); i++) {
            Coord src = sources.get(i);
            if (!grid.inBounds(src)) continue;
            if (dist[src.x()][src.y()] == UNREACHABLE) {
                dist[src.x()][src.y()]  = 0;
                owner[src.x()][src.y()] = i;
                queue.add(new int[]{src.x(), src.y(), i});
            }
        }
        while (!queue.isEmpty()) {
            int[] cur = queue.poll();
            int cx = cur[0], cy = cur[1], oi = cur[2];
            int d  = dist[cx][cy];
            for (Coord n : CoordUtils.neighbors(new Coord(cx, cy))) {
                if (!grid.inBounds(n) || grid.isBlocked(n)) continue;
                if (dist[n.x()][n.y()] > d + 1) {
                    dist[n.x()][n.y()]  = d + 1;
                    owner[n.x()][n.y()] = oi;
                    queue.add(new int[]{n.x(), n.y(), oi});
                }
            }
        }
    }

    /** Result of computing our Voronoi region from a candidate cell. */
    private record VoronoiArea(int rawCount, double weighted) {}

    /**
     * Cells we win the race to from {@code myDist}'s source, with hazard
     * weighting. A cell counts iff {@code myDist[c] < enemyDist[c]}, OR
     * {@code myDist[c] == enemyDist[c]} AND we are strictly longer than
     * the closest contesting enemy (we'd win the H2H if both arrived).
     * In solo (no enemies), {@code enemyDist} is all UNREACHABLE → every
     * reachable cell is owned, identical to a plain flood-fill.
     */
    private static VoronoiArea voronoiArea(int[][] myDist,
                                           EnemyReach enemyReach,
                                           List<BattleSnake> enemies,
                                           int myLength,
                                           BoardGrid grid) {
        int[][] enemyDist  = enemyReach.dist();
        int[][] enemyOwner = enemyReach.owner();
        int    raw      = 0;
        double weighted = 0.0;
        for (int x = 0; x < myDist.length; x++) {
            for (int y = 0; y < myDist[0].length; y++) {
                int md = myDist[x][y];
                if (md >= UNREACHABLE) continue;
                int ed = enemyDist[x][y];
                boolean own;
                if (md < ed) {
                    own = true;
                } else if (md == ed) {
                    int oi = enemyOwner[x][y];
                    own = oi >= 0 && myLength > enemies.get(oi).length();
                } else {
                    own = false;
                }
                if (own) {
                    raw++;
                    weighted += grid.isHazard(new Coord(x, y)) ? HAZARD_AREA_WEIGHT : 1.0;
                }
            }
        }
        return new VoronoiArea(raw, weighted);
    }

    private static int at(int[][] dist, Coord c) {
        if (c.x() < 0 || c.y() < 0 || c.x() >= dist.length || c.y() >= dist[0].length) {
            return UNREACHABLE;
        }
        return dist[c.x()][c.y()];
    }
}

package sneak.snaek;
import sneak.snaek.board.BoardGrid;
import sneak.snaek.board.CoordUtils;
import sneak.snaek.model.BattleSnake;
import sneak.snaek.model.Coord;
import sneak.snaek.model.GameState;
import sneak.snaek.model.Move;
import sneak.snaek.strategy.Bfs;
import sneak.snaek.strategy.MoveScorer;
import org.slf4j.Logger;
import java.util.*;
import static org.slf4j.LoggerFactory.getLogger;
import static sneak.snaek.model.Move.UP;
/**
 * Simple, fast decision engine -- one-ply greedy.
 *
 *   1. Build a safety filter (avoid OOB / bodies / losing H2H squares).
 *   2. Score each remaining move via {@link MoveScorer}
 *      (flood-fill survival + food-race bonus).
 *   3. Pick the highest scorer.
 */
public class SnakeEngine {
    private static final Logger log = getLogger(SnakeEngine.class);
    private static final Random RANDOM = new Random();
    public Move move(GameState game) {
        long start = System.nanoTime();
        BattleSnake you  = game.you();
        BoardGrid    grid = new BoardGrid(game);
        List<BattleSnake> enemies = game.board().snakes().stream()
                .filter(s -> !s.id().equals(you.id()))
                .toList();
        // Step 1: safety filter
        PathOptions safety = new PathOptions(grid)
                .avoidBlocked(you.head())
                .avoidHeadToHeadLosses(you.head(), you.length(), enemies);
        Set<Move> safe = safety.validMoves;
        if (safe.isEmpty()) {
            log.warn("No safe moves! Returning UP as last resort.");
            return UP;
        }
        if (safe.size() == 1) {
            Move only = safe.iterator().next();
            log.info("Single safe move: {}", only);
            return only;
        }
        // Step 2: hoist per-turn computations (identical for every candidate)
        Set<Coord> food = new HashSet<>(
                game.board().food() != null ? game.board().food() : List.of());
        Bfs.EnemyReach enemyReach = Bfs.computeEnemyReach(grid, enemies);
        boolean inHazard = grid.isHazard(you.head());
        double foodWeight = MoveScorer.computeFoodWeight(
                you.length(), you.health(), inHazard, enemies);
        Coord myTail = you.body().getLast();

        // Step 3: score & pick best
        Move best = UP;
        MoveScorer.Score bestScore = null;
        for (Move m : safe) {
            MoveScorer.Score s = MoveScorer.score(grid, you.head(), you.length(), you.health(), myTail,
                    m, enemies, food, enemyReach, foodWeight);
            log.debug("  candidate {} -> {}", m, s);
            if (bestScore == null || s.total() > bestScore.total()) {
                bestScore = s;
                best      = m;
            }
        }
        log.info("[{}] Turn {} | Head={} Health={} | Move={} {} ({}ms)",
                game.game().id(), game.turn(), you.head(), you.health(),
                best, bestScore, (System.nanoTime() - start) / 1_000_000);
        return best;
    }
    // PathOptions -- collision-safe move filter
    static class PathOptions {
        Set<Move> validMoves = new HashSet<>(Set.of(Move.values()));
        private final BoardGrid grid;
        PathOptions(BoardGrid grid) {
            this.grid = grid;
        }
        public PathOptions avoidBlocked(Coord head) {
            validMoves.removeIf(m -> grid.isBlocked(CoordUtils.neighbor(head, m)));
            return this;
        }
        public PathOptions avoidHeadToHeadLosses(Coord head, int myLength,
                                                  List<BattleSnake> enemies) {
            Set<Coord> danger = new HashSet<>();
            for (BattleSnake enemy : enemies) {
                if (enemy.length() >= myLength) {
                    for (Move m : Move.values()) {
                        danger.add(CoordUtils.neighbor(enemy.head(), m));
                    }
                }
            }
            Set<Move> filtered = new HashSet<>(validMoves);
            filtered.removeIf(m -> danger.contains(CoordUtils.neighbor(head, m)));
            if (!filtered.isEmpty()) validMoves = filtered;
            return this;
        }
        public Move randomMove() {
            if (validMoves.isEmpty()) return UP;
            List<Move> list = new ArrayList<>(validMoves);
            return list.get(RANDOM.nextInt(list.size()));
        }
    }
}

package sneak.snaek;
import sneak.snaek.board.BoardGrid;
import sneak.snaek.board.CoordUtils;
import sneak.snaek.model.BattleSnake;
import sneak.snaek.model.Coord;
import sneak.snaek.model.GameState;
import sneak.snaek.model.Move;
import sneak.snaek.strategy.Bfs;
import sneak.snaek.strategy.MoveScorer;
import org.slf4j.Logger;
import java.util.*;
import static org.slf4j.LoggerFactory.getLogger;
import static sneak.snaek.model.Move.UP;
/**
 * Simple, fast decision engine -- one-ply greedy.
 *
 *   1. Build a safety filter (avoid OOB / bodies / losing H2H squares).
 *   2. Score each remaining move via {@link MoveScorer}
 *      (flood-fill survival + food-race bonus).
 *   3. Pick the highest scorer.
 */
public class SnakeEngine {
    private static final Logger log = getLogger(SnakeEngine.class);
    private static final Random RANDOM = new Random();
    public Move move(GameState game) {
        long start = System.nanoTime();
        BattleSnake you  = game.you();
        BoardGrid    grid = new BoardGrid(game);
        List<BattleSnake> enemies = game.board().snakes().stream()
                .filter(s -> !s.id().equals(you.id()))
                .toList();
        // Step 1: safety filter
        PathOptions safety = new PathOptions(grid)
                .avoidBlocked(you.head())
                .avoidHeadToHeadLosses(you.head(), you.length(), enemies);
        Set<Move> safe = safety.validMoves;
        if (safe.isEmpty()) {
            log.warn("No safe moves! Returning UP as last resort.");
            return UP;
        }
        if (safe.size() == 1) {
            Move only = safe.iterator().next();
            log.info("Single safe move: {}", only);
            return only;
        }
        // Step 2: hoist per-turn computations (identical for every candidate)
        Set<Coord> food = new HashSet<>(
                game.board().food() != null ? game.board().food() : List.of());
        Bfs.EnemyReach enemyReach = Bfs.computeEnemyReach(grid, enemies);
        // Hazard damages whenever ANY body segment is inside, not just
        // the head — so even if the head is currently safe, a stretched-
        // out body in sauce is bleeding HP every turn and food urgency
        // should already be elevated.
        boolean inHazard = false;
        for (Coord seg : you.body()) {
            if (grid.isHazard(seg)) { inHazard = true; break; }
        }
        double foodWeight = MoveScorer.computeFoodWeight(
                you.length(), you.health(), inHazard, enemies);
        Coord myTail = you.body().getLast();

        // Step 3: score & pick best
        Move best = UP;
        MoveScorer.Score bestScore = null;
        for (Move m : safe) {
            MoveScorer.Score s = MoveScorer.score(grid, you.head(), you.length(), you.health(), myTail,
                    m, enemies, food, enemyReach, foodWeight);
            log.debug("  candidate {} -> {}", m, s);
            if (bestScore == null || s.total() > bestScore.total()) {
                bestScore = s;
                best      = m;
            }
        }
        log.info("[{}] Turn {} | Head={} Health={} | Move={} {} ({}ms)",
                game.game().id(), game.turn(), you.head(), you.health(),
                best, bestScore, (System.nanoTime() - start) / 1_000_000);
        return best;
    }
    // PathOptions -- collision-safe move filter
    static class PathOptions {
        Set<Move> validMoves = new HashSet<>(Set.of(Move.values()));
        private final BoardGrid grid;
        PathOptions(BoardGrid grid) {
            this.grid = grid;
        }
        public PathOptions avoidBlocked(Coord head) {
            validMoves.removeIf(m -> grid.isBlocked(CoordUtils.neighbor(head, m)));
            return this;
        }
        public PathOptions avoidHeadToHeadLosses(Coord head, int myLength,
                                                  List<BattleSnake> enemies) {
            Set<Coord> danger = new HashSet<>();
            for (BattleSnake enemy : enemies) {
                if (enemy.length() >= myLength) {
                    for (Move m : Move.values()) {
                        danger.add(CoordUtils.neighbor(enemy.head(), m));
                    }
                }
            }
            Set<Move> filtered = new HashSet<>(validMoves);
            filtered.removeIf(m -> danger.contains(CoordUtils.neighbor(head, m)));
            if (!filtered.isEmpty()) validMoves = filtered;
            return this;
        }
        public Move randomMove() {
            if (validMoves.isEmpty()) return UP;
            List<Move> list = new ArrayList<>(validMoves);
            return list.get(RANDOM.nextInt(list.size()));
        }
    }
}
